// T616 FreelancerReviewWriter — single-direction + append-only audit
const VALID_REVIEW_DIRECTIONS = ['CLIENT_TO_FREELANCER', 'FREELANCER_TO_CLIENT'] as const;

async submitReview(engagementId: string, direction: string, rating: number, reviewerId: string, targetId: string, comment: string): Promise<DataProcessResult<Record<string, unknown>>> {
  const tenantId = this.tenantContext.getTenantId(); // ALS only

  // ORDER 1: direction validation
  if (!(VALID_REVIEW_DIRECTIONS as readonly string[]).includes(direction)) {
    return DataProcessResult.failure('INVALID_DIRECTION', `Direction must be CLIENT_TO_FREELANCER or FREELANCER_TO_CLIENT`);
  }

  // ORDER 2: duplicate direction check
  const existing = await this.db.searchDocuments('reviews', { engagementId, direction });
  if (existing.data?.length) {
    await this.queue.enqueue('DuplicateReviewRejected', { tenantId, engagementId, direction, reviewerId, reason: 'ALREADY_REVIEWED_IN_DIRECTION' });
    return DataProcessResult.failure('DUPLICATE_DIRECTION', 'Review already submitted in this direction');
  }

  const reviewId = createHash('sha256').update(`${engagementId}:${direction}:${reviewerId}`).digest('hex').substring(0, 32);

  // ORDER 3: store review WITH comment (private scope)
  await this.db.storeDocument('reviews', { reviewId, engagementId, direction, rating, reviewerId, targetId, tenantId, comment, submittedAt: new Date().toISOString() });

  // ORDER 4 (DNA-8): audit WITHOUT comment — PII protection, BEFORE enqueue
  await this.db.storeDocument('review-audit', { reviewId, engagementId, direction, rating, reviewerId, targetId, tenantId, action: 'REVIEW_SUBMITTED' }); // comment intentionally omitted

  // Event: no comment in payload
  await this.queue.enqueue('FreelancerReviewSubmitted', { reviewId, engagementId, direction, rating, reviewerId, targetId, tenantId, submittedAt: new Date().toISOString() });
  return DataProcessResult.success({ reviewId, engagementId, direction });
}
